import { useState, useEffect } from "react";

function MoviePopup({ movie, onClose, onDelete, onUpdate }) {
    const [newTitle, setNewTitle] = useState("");

    // Reset the input whenever a new movie is selected
    useEffect(() => {
        if (movie) setNewTitle(movie.title);
    }, [movie]);

    if (!movie) return null;

    return (
        <div className="modal" onClick={onClose}>
            <div className="modal-content" onClick={(e) => e.stopPropagation()}>
                <img src={movie.poster} alt={movie.title} />

                {/* Modern Input instead of prompt */}
                <input
                    type="text"
                    value={newTitle}
                    onChange={(e) => setNewTitle(e.target.value)}
                    style={{ display: 'block', width: '100%', margin: '10px 0', padding: '10px' }}
                />

                <div className="modal-buttons">
                    <button onClick={() => {
                        onUpdate(movie.id, newTitle);
                        onClose(); // Close after saving
                    }}>Save Changes</button>

                    <button onClick={() => {
                        onDelete(movie.id);
                        onClose();
                    }}>Delete</button>

                    <button onClick={onClose}>Close</button>
                </div>
            </div>
        </div>
    );
}
